import{c as d,Q as a,j as t,m as r}from"./chunks/framework.BkjtU8k0.js";const n=JSON.parse('{"title":"文档导览","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":1779175532000}'),i={name:"guide/index.md"};function o(h,e,l,s,c,f){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="文档导览" tabindex="-1">文档导览 <a class="header-anchor" href="#文档导览" aria-label="Permalink to &quot;文档导览&quot;">​</a></h1><div class="doc-kicker">Start From The Right Door</div><p class="doc-lead"> Flyfish Viewer 官方文档同时承担组件主页、接入手册和成品交付说明。 文档围绕真实交付路径组织: 先确认支持格式和 Demo 表现，再选择 Vue3、Vue2 或 iframe 嵌入，最后了解安装和成品分发。 </p><div class="doc-link-row"><a href="https://doc.flyfish.dev" target="_blank" rel="noreferrer">官方文档</a><a href="https://viewer.flyfish.dev" target="_blank" rel="noreferrer">在线 Demo</a><a href="https://github.com/flyfish-dev/file-viewer" target="_blank" rel="noreferrer">GitHub 成品仓库</a><a href="/guide/quickstart">快速开始</a><a href="/guide/formats">支持格式</a><a href="/guide/usage">组件用法</a></div><h2 id="优秀之处" tabindex="-1">优秀之处 <a class="header-anchor" href="#优秀之处" aria-label="Permalink to &quot;优秀之处&quot;">​</a></h2><div class="doc-grid"><div class="doc-card"><h3>纯前端 Serverless</h3><p>主要解析和渲染工作在浏览器完成，减少后端转码服务、临时文件和任务队列带来的维护成本。</p></div><div class="doc-card"><h3>覆盖真实附件场景</h3><p>内置 59 个扩展名映射，覆盖 Office、PDF、OFD、CAD、Markdown、代码/文本、图片和视频。</p></div><div class="doc-card"><h3>按需加载更轻</h3><p>OFD、CAD、PDF、Office、Markdown 和代码高亮链路按格式异步加载，避免所有解析器一次性进入首屏。</p></div><div class="doc-card"><h3>阅读体验更完整</h3><p>Word 保留白色纸张和灰色页面底，PDF 支持缩放、导航窗格和宽度自适应，打开后默认就是可读状态。</p></div></div><h2 id="推荐阅读顺序" tabindex="-1">推荐阅读顺序 <a class="header-anchor" href="#推荐阅读顺序" aria-label="Permalink to &quot;推荐阅读顺序&quot;">​</a></h2><div class="doc-grid"><div class="doc-card"><h3>先看 Demo</h3><p>在线 Demo 提供按文件类型分组的样例文件盒子，点击样例即可打开并自动收起选择器，适合快速验收全部格式。</p></div><div class="doc-card"><h3>确认格式边界</h3><p>支持格式页列出当前注册的 59 个扩展名、对应渲染链路和真实业务里的适用边界。</p></div><div class="doc-card"><h3>选择接入方式</h3><p>Vue3 使用 <code>@flyfish-group/file-viewer3</code>，Vue2.7 使用 <code>@flyfish-group/file-viewer</code>；多系统复用、隔离依赖或带鉴权文件场景，优先考虑 iframe 嵌入。</p></div><div class="doc-card"><h3>准备发布分发</h3><p>成品分发说明了 npm 包、在线 Demo、官方文档和公开成品仓库之间的交付关系。</p></div></div><h2 id="当前重点能力" tabindex="-1">当前重点能力 <a class="header-anchor" href="#当前重点能力" aria-label="Permalink to &quot;当前重点能力&quot;">​</a></h2><ul><li>Word 视图保留灰色页面底和白色纸张，<code>.docx</code> 会按当前可用宽度自适应缩放，长文档缺少显式分页时也会补足视觉分页。</li><li>PDF 视图支持宽度自适应、缩放工具栏、页码状态和可显隐导航窗格。</li><li>OFD 使用 <code>DLTech21/ofd.js</code> 的浏览器端解析和渲染能力，并保持按需异步加载。</li><li>CAD 支持 DXF 在线预览，DWG 作为兼容入口给出转换提示，避免引入不合适的运行时授权链路。</li><li>代码和文本使用 <code>highlight.js</code> 轻量高亮，HTML 会按源码展示，不在预览器里执行。</li></ul><h2 id="常用入口" tabindex="-1">常用入口 <a class="header-anchor" href="#常用入口" aria-label="Permalink to &quot;常用入口&quot;">​</a></h2><table tabindex="0"><thead><tr><th>你要做什么</th><th>推荐页面</th></tr></thead><tbody><tr><td>想最快跑起来</td><td><a href="/guide/quickstart">快速开始</a></td></tr><tr><td>想确认所有格式</td><td><a href="/guide/formats">支持格式</a></td></tr><tr><td>想看示例文件和回归建议</td><td><a href="/guide/demo">Demo 说明</a></td></tr><tr><td>想在 Vue 3 中接入</td><td><a href="/guide/quickstart-vue3">Vue3 集成</a></td></tr><tr><td>想在 Vue2.7 中接入</td><td><a href="/guide/quickstart-vue2">Vue2 集成</a></td></tr><tr><td>想让多个系统共用预览器</td><td><a href="/guide/iframe">Iframe 嵌入</a></td></tr><tr><td>想了解参数和事件</td><td><a href="/guide/usage">组件用法</a></td></tr><tr><td>想下载成品或二开</td><td><a href="/guide/distribution">发布与成品分发</a></td></tr></tbody></table><div class="doc-note"> 如果你只是想快速判断项目是否适合业务，建议先打开 <a href="https://viewer.flyfish.dev" target="_blank" rel="noreferrer">viewer.flyfish.dev</a>，再用自己的真实附件补一轮回归。 </div>',13)])])}const v=d(i,[["render",o]]);export{n as __pageData,v as default};
